
import { NextResponse } from 'next/server';
import { generateKissVideo } from '@/ai/flows/generate-kiss-video';
import { activateUserSubscriptionAdmin } from '@/lib/firebase/firebase-admin';

export async function POST(request: Request) {
  try {
    const body = await request.json();
    const { userId, image1DataUri, image2DataUri } = body;

    if (!userId || !image1DataUri || !image2DataUri) {
      return NextResponse.json({ error: 'Missing required fields.' }, { status: 400 });
    }
    
    // Step 1: Upgrade the user's account to Pro. This is the most critical part.
    await activateUserSubscriptionAdmin(userId);

    // Step 2: Proceed with the video generation.
    const result = await generateKissVideo({ image1DataUri, image2DataUri });

    if (result.error) {
        return NextResponse.json({ error: result.error }, { status: 500 });
    }

    // Note: We don't need to decrement credits here because activateUserSubscriptionAdmin sets them to 15,
    // and this is the first video they generate after purchasing. The webhook is the ultimate source of truth.
    
    return NextResponse.json(result, { status: 200 });

  } catch (e: any) {
    const message = e.stack || e.message || 'An unknown error occurred.';
    return NextResponse.json(
        { error: `An unexpected server error occurred during the upgrade & generation process. Details: ${message}` },
        { status: 500 }
    );
  }
}
