// src/lib/firebase/firebase-admin.ts
import { initializeApp as initializeAdminApp, getApps as getAdminApps, type App as AdminApp } from 'firebase-admin/app';
import { getFirestore as getAdminFirestore, type Firestore as AdminFirestore, serverTimestamp, increment, doc, setDoc, getDoc, Timestamp } from 'firebase-admin/firestore';
import { getAuth as getAdminAuth, type Auth as AdminAuth } from 'firebase-admin/auth';
import { firebaseConfig } from './config';
import type { UserProfile } from './types';

let adminApp: AdminApp;
let adminAuth: AdminAuth;
let adminDb: AdminFirestore;

// Initialize Firebase Admin SDK
if (getAdminApps().length === 0) {
    adminApp = initializeAdminApp({
        projectId: firebaseConfig.projectId,
    });
} else {
    adminApp = getAdminApps()[0];
}

adminAuth = getAdminAuth(adminApp);
adminDb = getAdminFirestore(adminApp);

export const admin = {
  auth: adminAuth,
  db: adminDb,
  app: adminApp,
};

// Server-side database functions using Admin SDK

export async function activateUserSubscriptionAdmin(uid: string) {
    if (!uid) {
        console.error("activateUserSubscriptionAdmin was called without a UID.");
        throw new Error("UID is required to activate a subscription.");
    }
    const userRef = doc(adminDb, 'users', uid);
    
    // The webhook is the source of truth.
    await setDoc(userRef, {
        isSubscribed: true,
        credits: 15,
        subscriptionEndDate: null, // Clear any previous cancellation date on renewal
    }, { merge: true });
}

export async function cancelUserSubscriptionAdmin(uid: string, endsAt: string) {
    if (!uid) {
        console.error("cancelUserSubscriptionAdmin was called without a UID.");
        throw new Error("UID is required to cancel a subscription.");
    }
    const userRef = doc(adminDb, 'users', uid);
    
    // Set the date when the subscription will no longer be valid.
    await setDoc(userRef, {
        subscriptionEndDate: Timestamp.fromDate(new Date(endsAt)),
    }, { merge: true });
}


export async function checkUserSubscriptionAdmin(uid: string): Promise<UserProfile | null> {
  const userRef = doc(adminDb, 'users', uid);
  const docSnap = await getDoc(userRef);

  if (docSnap.exists()) {
    const data = docSnap.data();
    
    let isSubscribed = data.isSubscribed || false;
    
    // If there's a subscription end date, check if it's in the past.
    if (data.subscriptionEndDate) {
      const endDate = (data.subscriptionEndDate as Timestamp).toDate();
      if (new Date() > endDate) {
        isSubscribed = false;
      }
    }

    const profile: UserProfile = {
      uid: data.uid,
      email: data.email,
      credits: data.credits,
      createdAt: data.createdAt?.toDate ? data.createdAt.toDate().toISOString() : new Date().toISOString(),
      lastLogin: data.lastLogin?.toDate ? data.lastLogin.toDate().toISOString() : new Date().toISOString(),
      subscriptionEndDate: data.subscriptionEndDate?.toDate ? data.subscriptionEndDate.toDate().toISOString() : null,
      isSubscribed: isSubscribed,
    };

    // If subscription has expired, update the database record for consistency.
    if (data.isSubscribed && !isSubscribed) {
        await setDoc(userRef, { isSubscribed: false }, { merge: true });
    }
    
    return profile;
  } else {
    return null;
  }
}

export async function decrementUserCreditsAdmin(uid: string) {
    const userRef = doc(adminDb, 'users', uid);
    const docSnap = await getDoc(userRef);

    if (!docSnap.exists()) {
        throw new Error("User profile does not exist.");
    }
    
    const userProfile = await checkUserSubscriptionAdmin(uid);
    if (!userProfile || (!userProfile.isSubscribed && userProfile.credits <= 0)) {
        throw new Error("User has no credits to decrement.");
    }

    const currentCredits = docSnap.data().credits || 0;
    if (currentCredits > 0) {
        await setDoc(userRef, {
            credits: increment(-1),
        }, { merge: true });
    } else {
        await setDoc(userRef, {
            isSubscribed: false,
        }, { merge: true });
        throw new Error("User has no credits to decrement.");
    }
}
